set -e
echo "=== TradingApp Phase 2.1 — déploiement en un bloc ==="

# 1. Décoder l'archive (base64 → tar.gz → fichiers dans /tmp)
mkdir -p /tmp/phase21
cd /tmp/phase21
echo "" | base64 -d | tar xz
ls -la

# 2. Copier dans /opt/tradingapp/ avec bons droits
cp -f extractor.py news_collector.py agent_news.py requirements.txt /opt/tradingapp/
chown tradingapp:tradingapp /opt/tradingapp/extractor.py /opt/tradingapp/news_collector.py /opt/tradingapp/agent_news.py /opt/tradingapp/requirements.txt
echo "✓ Fichiers copiés"

# 3. Installer la nouvelle dépendance (openai)
echo ""
echo "=== Pip install ==="
sudo -u tradingapp bash -c 'cd /opt/tradingapp && source venv/bin/activate && pip install -r requirements.txt -q && echo DEPS_OK'

# 4. Test rapide de l'extracteur
echo ""
echo "=== Test extracteur DeepSeek (3 cas) ==="
sudo -u tradingapp bash -c 'cd /opt/tradingapp && source venv/bin/activate && set -a && source .env && set +a && python extractor.py'

# 5. Redémarrer le service
echo ""
echo "=== Restart service ==="
systemctl restart tradingapp-news-collector
sleep 5
systemctl status tradingapp-news-collector --no-pager | head -10

# 6. Logs récents
echo ""
echo "=== Logs des 2 dernières minutes ==="
journalctl -u tradingapp-news-collector --since '2 minutes ago' --no-pager | tail -30

# 7. Nettoyage
rm -rf /tmp/phase21

echo ""
echo "=== Phase 2.1 DEPLOYEE ==="
